) as v(identifier, trade_code, category_code, unit_code, text, material, labor)
join public.organizations o
  on o.slug = 'demo'
join public.trades t
  on t.organization_id = o.id and lower(t.code) = lower(v.trade_code) and t.deleted_at is null
join public.categories c
  on c.organization_id = o.id and lower(c.code) = lower(v.category_code) and c.deleted_at is null
join public.units u
  on u.organization_id = o.id and lower(u.code) = lower(v.unit_code) and u.deleted_at is null
where not exists (
  select 1 from public.cost_items ci
  where ci.organization_id = o.id
    and lower(ci.identifier) = lower(v.identifier)
    and ci.deleted_at is null
);

